1468: static unsigned getVectorTypeBreakdownMVT(MVT VT, MVT &IntermediateVT,
1469:                                           unsigned &NumIntermediates,
1470:                                           MVT &RegisterVT,
1471:                                           TargetLoweringBase *TLI) {
1472:   // Figure out the right, legal destination reg to copy into.
1473:   ElementCount EC = VT.getVectorElementCount();
1474:   MVT EltTy = VT.getVectorElementType();
1475: 
1476:   unsigned NumVectorRegs = 1;
1477: 
1478:   // Scalable vectors cannot be scalarized, so splitting or widening is
1479:   // required.
1480:   if (VT.isScalableVector() && !isPowerOf2_32(EC.getKnownMinValue()))
1481:     llvm_unreachable(
1482:         "Splitting or widening of non-power-of-2 MVTs is not implemented.");
1483: 
1484:   // FIXME: We don't support non-power-of-2-sized vectors for now.
1485:   // Ideally we could break down into LHS/RHS like LegalizeDAG does.
1486:   if (!isPowerOf2_32(EC.getKnownMinValue())) {
1487:     // Split EC to unit size (scalable property is preserved).
1488:     NumVectorRegs = EC.getKnownMinValue();
1489:     EC = ElementCount::getFixed(1);
1490:   }
1491: 
1492:   // Divide the input until we get to a supported size. This will
1493:   // always end up with an EC that represent a scalar or a scalable
1494:   // scalar.
1495:   while (EC.getKnownMinValue() > 1 &&
1496:          !TLI->isTypeLegal(MVT::getVectorVT(EltTy, EC))) {
1497:     EC = EC.divideCoefficientBy(2);
1498:     NumVectorRegs <<= 1;
1499:   }
